      id: `${Date.now()}-${++idCounter}-${slugify(path12.basename(markdownPath, ".md")) || "interview"}`,
      sessionID,
      idea: title || path12.basename(markdownPath, ".md"),
      markdownPath,
      createdAt: nowIso(),
      status: "active",
      baseMessageCount: messages.length
